import React, { useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { authService } from "../services";
import Sidebar from "../components/Sidebar";
import "../styles/Dashboard.css";

const AdminDashboard = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleLogout = () => {
    authService.logout();
    navigate("/admin/login");
  };

  const menuItems = [
    {
      name: "Dashboard",
      icon: "📊",
      path: "/admin/dashboard",
      onClick: () => navigate("/admin/dashboard"),
    },
    {
      name: "Loads",
      icon: "📦",
      path: "/loads",
      onClick: () => navigate("/loads"),
    },
    {
      name: "Create Load",
      icon: "➕",
      path: "/create-load",
      onClick: () => navigate("/create-load"),
    },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <aside className={`dashboard-sidebar ${sidebarOpen ? "open" : "closed"}`}>
        <div className="sidebar-header">
          <h2 className="sidebar-title">🛡️ Admin</h2>
          <button
            className="sidebar-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            {sidebarOpen ? "✕" : "☰"}
          </button>
        </div>

        <nav className="sidebar-menu">
          {menuItems.map((item) => (
            <button
              key={item.path}
              className={`menu-item ${isActive(item.path) ? "active" : ""}`}
              onClick={() => {
                navigate(item.path);
                if (window.innerWidth < 768) setSidebarOpen(false);
              }}
            >
              <span className="menu-icon">{item.icon}</span>
              {sidebarOpen && <span className="menu-label">{item.name}</span>}
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <button onClick={handleLogout} className="btn-logout">
            🚪 {sidebarOpen && "Logout"}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="dashboard-main">
        <div className="dashboard-content">
          <div className="info-card admin-info">
            <h3>Admin Control Panel</h3>
            <p>Control and manage the load management system.</p>
            <ul>
              <li>Create and manage loads</li>
              <li>Track load status</li>
              <li>View all available loads</li>
              <li>Edit or delete loads</li>
              <li>Monitor system activity</li>
              <li>Admin user management</li>
            </ul>
            <button onClick={() => navigate("/loads")} className="btn-primary">
              View All Loads
            </button>
          </div>

          <div className="quick-stats">
            <div className="stat-card">
              <h4>Email</h4>
              <p>{user?.email}</p>
            </div>
            <div className="stat-card">
              <h4>Role</h4>
              <p className="role-badge admin-badge">
                {user?.role?.toUpperCase()}
              </p>
            </div>
            <div className="stat-card">
              <h4>Access Level</h4>
              <p>Full Administrative Access</p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
